{{ config(materialized='view') }}

WITH material_data AS (
    SELECT * FROM {{ ref('int_material_transformed') }}
),

descriptions AS (
    SELECT * FROM {{ ref('int_material_descriptions') }}
)

SELECT
    m.*,
    d.ProductDescription
FROM material_data m
INNER JOIN descriptions d
    ON m.Product = d.Product0
ORDER BY m.Product
